import Header from './components/Header'
import Footer from './components/Footer';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import RedirectToHome from './routing/RedirectToHome';
import React, { useEffect, useState, useRef, Suspense} from 'react';
import { ThemeProvider } from 'styled-components';
import { Cursor } from './libs/contextCursor/chunks';
import contextMode from './libs/contextCursor/modes/contextMode';
import propNames from './libs/contextCursor/propNames';
import useMutationObserver from './helpers/hooks/useMutationObserver';
import useMobile from './helpers/hooks/useMobile';
import { Helmet } from 'react-helmet';
import darkLogo from './assets/images/darkLogo.svg';
import Loader from './components/Loader'

const Home = React.lazy(() => import('./pages/Home'));
const BlogPage = React.lazy(() => import('./blog/pages/BlogPage'));
const BlogHomePage = React.lazy(() => import('./blog/pages/BlogHomePage'));
const Portfolio = React.lazy(() => import('./pages/Portfolio'));
const Contact = React.lazy(() => import('./pages/Contact'));
const CareerEmpty = React.lazy(() => import('./pages/CareerEmpty'));
// const CareerFilled = React.lazy(() => import('./pages/CareerFilled'));
const Vacancy = React.lazy(() => import('./pages/Vacancy'));
// const Backoffice = React.lazy(() => import('./pages/Backoffice'));
// const Ain = React.lazy(() => import('./pages/Ain'));

function App() {
	const cursorRef = useRef();
	const cursorActionsRef = useRef();
	const lastCursorProp = useRef();
	const lastMouseProps = useRef({
		x: 0,
		y: 0,
	});
	const appRef = useRef();
	const isHovered = useRef(false);
	const cursorTarget = useRef(null);
	const isMobile = useMobile();
	const location = window.location
	
	const [isBright, setIsBright] = useState(true);
	const [interactElements, setInteractElements] = useState([]);

	function onMutation () {
		setInteractElements(document.querySelectorAll(`[${propNames.dataAttr}]`));
	}
	
	useMutationObserver(appRef,onMutation);

	useEffect(()=> {
		if (!isMobile) {
			onMutation();
		}
	},[isMobile])

	useEffect(()=> {
		if (!isMobile) {
			cursorActionsRef.current = contextMode(
				cursorRef.current,
				interactElements,
				isHovered,
				cursorTarget,
				lastCursorProp,
				lastMouseProps);
			return function () {
				cursorActionsRef.current();
			}
		}
	},[interactElements,isBright,isMobile,location.pathname])

	const theme = {isBright, setIsBright}

	return (
		<>
			<Cursor
				isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}
				reference={cursorRef}
				radius='20'
				parallaxIndex='10'
				hoverPadding='6'
				cursorX={lastCursorProp.current?.x ? lastCursorProp.current.x : 10}
				cursorY={lastCursorProp.current?.y ? lastCursorProp.current.y : 10}
			/>
			<div id='app' ref={appRef}>
				<BrowserRouter>
					<ThemeProvider theme={theme}>
						
							<Helmet>
								<meta id='description' property='og:description' name='og:description' content='Outsource your web development and UX/UI tasks to professionals and enjoy the process' />
								<meta id='og-title' property='og:title' content='Jito' />
								<meta id='og-image' property='og:image' content={darkLogo} />
								<meta id='url' property='og:site_name' content='Jito.dev'/>
							</Helmet>
							<Header />
								<Routes>
									<Route path='/home' element={<Suspense fallback={<Loader />}><Home onMutation={onMutation}/></Suspense>} />
									<Route path='/blog'>
										<Route index element={<Suspense fallback={<Loader />}><BlogHomePage isBright={isBright} /></Suspense>} />
										<Route path='/blog/:id' element={<Suspense fallback={<Loader />}><BlogPage isBright={isBright} /></Suspense>} />
									</Route>
									<Route path='/contact' element={<Suspense fallback={<Loader />}><Contact /></Suspense>} />
									<Route path='/portfolio'>
										<Route index element={<Suspense fallback={<Loader />}><Portfolio /></Suspense>} />
										{/* <Route path='/portfolio/backoffice' element={<Suspense><Backoffice /></Suspense>} /> */}
										{/* <Route path='/portfolio/ain' element={<Suspense><Ain /></Suspense>} /> */}
									</Route>
									<Route path='/career'>
										<Route index element={<Suspense fallback={<Loader />}><CareerEmpty /></Suspense>} />
										<Route path='/career/:id' element={<Suspense fallback={<Loader />}><Vacancy /></Suspense>} />
									</Route>
									<Route path='*' element={<Suspense fallback={<Loader />}><RedirectToHome /></Suspense>} />
								</Routes>
							<Footer />
					
					</ThemeProvider>
				</BrowserRouter>
			</div>
		</>
	);
}

export default App;
