import styled from 'styled-components';

const StyledCursor = styled.div`
	position: fixed;
	z-index: 9999;
	pointer-events: none;
	border-radius: 200px;
	background-color: rgb(${props => props.isBright ? '0, 0, 0, 0.2' : ' 255, 255, 255, 0.2'});
	transition: 0.2s;
	transition-property: scale;

	&.c-cursor_active {
	background-color: rgb(${props => props.isBright ? '0, 0, 0, 0.2' : ' 255, 255, 255, 0.2'});
	transition: 0.1s;
	}

	&.c-cursor-lift_active {
	background-color: rgba(0,0,0,0);
	transition: 0.1s;
	}
`;

const Cursor = (props) => {
	return (
		<StyledCursor
		ref={props.reference}
		className='c-cursor'
		isBright={props.isBright}
		style={{
			transform: `translate(${window.event?.clientY ? window.event.clientY : `${props.cursorY}`}px, ${window.event?.clientX ? window.event.clientX : `${props.cursorX}`}px)`,
			height: `${props.radius}px`,
			width: `${props.radius}px`
		}}
		/>
	) 
};

export default Cursor;
