import React, { useContext } from 'react';
import * as Styled from './styles';
import disableScroll from 'disable-scroll';
import { useLocation } from 'react-router-dom';
import { ThemeContext } from 'styled-components';
import Button from '../Button';

const NavMenu = ({ isMenuOpen, setIsMenuOpen }) => {
	const {isBright} = useContext(ThemeContext);

	const location = useLocation();
	function onLinkClick () {
		setIsMenuOpen(false);
		disableScroll.off();
	}

	return (
		<Styled.TransitionContainer isMenuOpen={isMenuOpen}>
			<Styled.MenuContainer isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}>
				<Styled.NavContainer>
					<Styled.Link onClick={onLinkClick} to={'/home'}>Home</Styled.Link>
					<Styled.HashLink onClick={onLinkClick} to={'/home#services'}>Services</Styled.HashLink>
					<Styled.Link onClick={onLinkClick} to={'/portfolio'} >Portfolio</Styled.Link>
					<Styled.Link onClick={onLinkClick} to={'/career'}>Career</Styled.Link>
					<Styled.Link onClick={onLinkClick} to={'/blog'} href='#'>Blog</Styled.Link>
				</Styled.NavContainer>
				<Styled.ButtonContainer>
					<a href='#contact'>
						<Button
							onClick={onLinkClick}
							colorReverse={location.pathname.slice(0,5) === '/blog' ? !isBright : false}
						>
							Contact us
						</Button>
					</a>
				</Styled.ButtonContainer>
			</Styled.MenuContainer>
	</Styled.TransitionContainer>
	);
};

export default NavMenu;