import React from 'react'
import styled from 'styled-components';
import logo from '../../assets/images/logo.svg';
import darkLogo from '../../assets/images/darkLogo.svg';
import smallLogo from '../../assets/images/Jitoid.svg';
import smallDarkLogo from '../../assets/images/JitoidDark.svg';
import { useNavigate } from 'react-router-dom';

export const StyledLogo = styled.img`
    cursor: pointer;
    z-index: 20;
    transition: 0.2s;
    height: ${props => props.small ? '32px' : '40px'};
    width: auto;
`;

export default function Logo({ small, isBright }) {
  const navigate = useNavigate();
  return (
    <StyledLogo
      alt='logo'
      small={small}
      src={isBright ? small ? smallDarkLogo : darkLogo : small ? smallLogo : logo}
      onClick={() => navigate('/home')}
    />
  )
}
