import React, { useContext } from 'react'
import Logo from '../Logo';
import * as Styled from './styles';
import useMobile from '../../helpers/hooks/useMobile';
import useTablet from '../../helpers/hooks/useTablet';
import { useInView } from 'react-intersection-observer';
import { ThemeContext } from 'styled-components';
import { useLocation, useNavigate } from 'react-router-dom';
import doubleOptions from '../../helpers/functions/doubleOptions';

export default function Footer() {
	const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
	const isTablet = useTablet();
	const {isBright} = useContext(ThemeContext);
	const location = useLocation();
	const navigate = useNavigate();
	const isDesktop = !isMobile && !isTablet;

	return (
		<Styled.Footer
			isTablet={isTablet}
			isMobile={isMobile}
			isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}
			location={location.pathname.slice(0,5)}
		>
			<Styled.MainContent  ref={ref} inView={inView}>
				<Styled.Navigation>
					<Logo small isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}/>
					<Styled.Email>sales@jito.dev</Styled.Email>
					<Styled.Email>hr@jito.dev</Styled.Email>
				</Styled.Navigation>
				<Styled.HireButtonContainer isVisible={
					location.pathname.slice(0,5) === '/blog'
						? doubleOptions(isMobile || isDesktop,true,false)
						: false}>
					<Styled.HireButton onClick={()=> navigate('/contact')} data-ccursor>Hire us</Styled.HireButton>
				</Styled.HireButtonContainer>
				<Styled.Navigation>
					<Styled.Link>Terms and Conditions</Styled.Link>
					<Styled.Link>Privacy Policy</Styled.Link>
					<Styled.Link>@Jito 2022</Styled.Link>
				</Styled.Navigation>
			</Styled.MainContent>
		</Styled.Footer>
	)
}