import React from 'react';
import styled from 'styled-components';
import doubleOptions from '../../helpers/functions/doubleOptions';

const StyledButton = styled.button`
	padding: 20px 45px;
	background-color: ${props => props.colorReverse ? '#FFFFFF' : '#02010F'};
	border: 1px solid #02010F;
	border-radius: 40px;
	cursor: pointer;
	font-family: 'Poppins';
	font-weight: 600;
	font-size: 14px;
	line-height: 16px;
	transition: 0.2s;
	color: ${props => props.colorReverse ? '#02010F' : '#FFFFFF'};
	width: ${props => props.isTablet ? doubleOptions(props.isMobile,'280px','280px') : '280px'};
	&:hover {
		color: #FFFFFF;
		border: 0.5px solid ${props => props.colorReverse ? '#FFFFFF' : '#02010F'};
		background-color: ${props => props.colorReverse ? '#02010F' : '#3A3A44'};
	}
`;

export default function Button({ isTablet, isMobile, withBorder, colorReverse, children, ...props }) {
	return (
		<StyledButton data-ccursor isMobile={isMobile} withBorder={withBorder} colorReverse={colorReverse} {...props}>
			{children}
		</StyledButton>
	)
}
