import styled from 'styled-components';
import { NavLink } from 'react-router-dom';
import { HashLink as HashNavLink} from 'react-router-hash-link';
import doubleOptions from '../../helpers/functions/doubleOptions';

export const Navigation = styled.nav`
	z-index: 20;
	display: flex;
	justify-content: center;
	align-items: center;
`;

const LinkStyles = `
	font-family: 'Inter';
	font-weight: 400;
	font-size: 16px;
	line-height: 24px;
	text-transform: uppercase;
	color: #9A99A2;
	cursor: pointer;
	text-decoration: none;
	transition: 0.4s;
	border-radius: 30px;
	padding: 0 5px;

	&:not(:last-of-type) {
		margin-right: 30px;
	}

	@media (max-width: 1150px) {
		&:not(:last-of-type) {
		margin-right: 20px;
		}
	}
`;
export const Link = styled(NavLink)`
	${LinkStyles}
`;

export const HashLink = styled(HashNavLink)`
	${LinkStyles}
`;

export const ThemeSwitcher = styled.div`
	position: relative;
    border-radius: 50px;
    display: flex;
    cursor: pointer;
    width: 48px;
    height: 32px;
    transition: 0.2s;
`;

export const ThemeButton = styled.div`
	top: -1px;
	position: absolute;
	width: 32px;
	height: calc(100% + 2px);
	transition: 0.2s;
	border-radius: 50px;
	display: flex;
    justify-content: center;
    align-items: center;
`;

export const ContactButton = styled.a`
	font-family: 'Inter';
	font-weight: 700;
	font-size: 16px;
	line-height: 16px;
	cursor: pointer;
	text-decoration: none;
	transition: 0.2s;
	padding: 16px 40px;
	border-radius: 40px;
`;

export const MenuItem = styled.div`
`;

export const ProgressBar = styled.div`
	height: 8px;
	widht: 100%;
	transition: 0.2s;
`;

export const ProgressBarPivot = styled.div`
	height: 100%;
	width: ${props => props.pivotPercent}%;
	transition: 0.1s;
`;

export const ButtonContainer = styled.div``;

export const HeaderContainer = styled.div`
	background-color: ${props => props.isBright ? '#fff' : '#1C1B20'};
	z-index: 1000;
	width: 100%;
	position: fixed;
	top: ${props => props.isHeaderHidden ? '-80px' : '0'};
	transition: 0.2s;

	& ${ProgressBar} {
		background-color: ${props => props.isBright ? '#F3F3F7' : '#46454F'};
	}

	& ${ProgressBarPivot} {
		background-color: ${props => props.isBright ? '#ACC935' : '#ACC935'};
	}

    & ${ThemeSwitcher} {
      border: 1px solid ${props => props.isBright ? '#CCCCCF' : '#46454F'};
      background-color: inherit;
	  border: 1px solid ${props => props.isBright ? '#02010F' : '#FFFFFF'};
	  justify-content: ${props => props.isBright ? 'flex-start' : 'flex-end'};
    }

	& ${ThemeButton} {
		background-color: ${props => props.isBright ? '#02010F' : '#FFFFFF'};
	}

    & ${MenuItem} {
      background: ${props => props.isBright ? '#000' : '#fff'};
    }

    & ${Link}.active {
      color: ${props => props.isBright ? '#02010F' : '#FFFFFF'};
    }

    & ${ContactButton} {
      color: #02010F;
      background-color: #FFFFFF;
      border: 1px solid #02010F;
    }
`;

export const Header = styled.header`
    max-width: 1176px;
    @media (max-width: 1440px) {
        max-width: ${props => props.isMobile ? '100%' : '90%'};
        ${props => props.isTablet && 'width: 100%;'}
    }
    margin: 0 auto;
    height: 80px;
	display: ${props => props.isTablet ? 'flex' : 'grid'};
    ${props => props.isTablet ? ' justify-content: space-between;' : 'grid-template-columns: 1fr 1fr 1fr;'}
	align-items: center;
    padding: ${props => props.isTablet ? doubleOptions(props.isMobile,'0 16px','0') : '0'};
    align-items: center;
 
    z-index: 1000;
    transition: 0.2s;

	& ${ButtonContainer} {
		display: flex;
		align-items: center;
		justify-content: flex-end;
		gap: 32px;
		@media (max-width: 1105px) {
			gap: 12px;
			& button {
				${props => !props.isTablet && 'padding: 16px 36px;'}
			}
		}
		@media (max-width: 1000px) {
			gap: 18px;
		}
	}

`;

export const StyledBurger = styled.button`
	top: 5%;
	left: 2rem;
	display: flex;
	flex-direction: column;
	justify-content: space-around;
	width: 2rem;
	height: 2rem;
	background: transparent;
	border: none;
	cursor: pointer;
	padding: 0;
	z-index: 20;

	&:focus {
		outline: none;
	}

	${MenuItem} {
		width: 2rem;
		height: 0.1rem;
		border-radius: 10px;
		transition: all 0.3s linear;
		position: relative;
		transform-origin: 1px;

		:first-child {
		transform: rotate(${({ open }) => open ? '45deg' : '0'});
		}

		:nth-child(2) {
		opacity: ${({ open }) => open ? '0' : '1'};
		transform: translateX(${({ open }) => open ? '20px' : '0'});
		}

		:nth-child(3) {
		transform: rotate(${({ open }) => open ? '-45deg' : '0'});
		}
	}
`;
