import React from 'react'
import { useState, useContext, useRef } from 'react';
import Logo from '../Logo';
import * as Styled from './styles';
import useTablet from '../../helpers/hooks/useTablet';
import useMobile from '../../helpers/hooks/useMobile';
import NavMenu from '../NavMenu/NavMenu';
import disableScroll from 'disable-scroll';
import { ReactComponent as Bright } from '../../assets/images/Bright.svg';
import { ReactComponent as Night } from '../../assets/images/Night.svg';
import { useLocation, useNavigate } from 'react-router-dom';
import { ThemeContext } from 'styled-components';
import Button from '../../components/Button';
import { useEffect } from 'react';

export default function Header() {
	const {isBright, setIsBright} = useContext(ThemeContext);
	const wasThemeSwitched = useRef(false);
	const wasThemeRecentlySwitched = useRef(false);
	const [isNavOpen, setIsNavOpen] = useState(false);
	const [isHeaderHidden, setIsHeaderHidden] = useState(false);
	const [pivotPercent, setPivotPersent] = useState(0);
	const isTablet = useTablet();
	const isMobile = useMobile();
	const lastScrollData = useRef(null);
	const navigate = useNavigate();
	const location = useLocation();
	isNavOpen ? disableScroll.on() : disableScroll.off();

	function onHandleScroll (e) {
		const height = document.documentElement;
		const scrollTop = height.scrollTop || document.body.scrollTop;
		const scrollHeight = height.scrollHeight || document.body.scrollHeight;
		const percent = scrollTop / (scrollHeight - height.clientHeight) * 100;
		setPivotPersent(Math.round(percent));

		if (scrollTop > lastScrollData.current && !wasThemeRecentlySwitched.current){
			setIsHeaderHidden(true);
		} else if (scrollTop < lastScrollData.current) {
			setIsHeaderHidden(false);
		}
		lastScrollData.current = scrollTop <= 0 ? 0 : scrollTop; 
	}

	useEffect(()=> {
		if (wasThemeSwitched.current) {
			wasThemeRecentlySwitched.current = true;
		}
		return () => wasThemeRecentlySwitched.current = false;
	},[isBright])

	useEffect(()=> {
		document.addEventListener('scroll', e =>  onHandleScroll())
		return document.removeEventListener('scroll', e => onHandleScroll())
	},[])

	const handleThemeSwitch =  () => {
		wasThemeSwitched.currnet = true;
		setIsBright(!isBright);
	}

  	return (
	<Styled.HeaderContainer
		isHeaderHidden={isHeaderHidden}
		isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}
	>
		<Styled.Header isTablet={isTablet} isMobile={isMobile}>
			<Logo isBright={location.pathname.slice(0,5) === '/blog' ? isBright : true}/>
			{isTablet ? (
				<Styled.ButtonContainer>
					{location.pathname.slice(0,5) === '/blog' && (
						<Styled.ThemeSwitcher data-ccursor isBright={isBright} onClick={handleThemeSwitch}>
							<Styled.ThemeButton>{isBright ? <Bright /> : <Night />}</Styled.ThemeButton>
						</Styled.ThemeSwitcher>
					)}
					<Styled.StyledBurger open={isNavOpen} onClick={() => setIsNavOpen(!isNavOpen)}>
						<Styled.MenuItem />
						<Styled.MenuItem />
						<Styled.MenuItem />
					</Styled.StyledBurger>
					<NavMenu setIsMenuOpen={setIsNavOpen} isMenuOpen={isNavOpen}/>
				</Styled.ButtonContainer>
			) : (
				<>
					<Styled.Navigation>
						<Styled.Link data-ccursor to={'/home'}>Home</Styled.Link>
						<Styled.HashLink data-ccursor to={'/home#services'}>Services</Styled.HashLink>
						<Styled.Link data-ccursor to={'/portfolio'} >Portfolio</Styled.Link>
						<Styled.Link data-ccursor to={'/career'}>Career</Styled.Link>
						<Styled.Link data-ccursor to={'/blog'} href='#'>Blog</Styled.Link>
					</Styled.Navigation>
					<Styled.ButtonContainer>
						{location.pathname.slice(0,5) === '/blog' && (
							<Styled.ThemeSwitcher data-ccursor isBright={isBright} onClick={(e) => setIsBright(!isBright)}>
								<Styled.ThemeButton>{isBright ? <Bright /> : <Night />}</Styled.ThemeButton>
							</Styled.ThemeSwitcher>
						)}
						{location.pathname.slice(0,5) === '/home' || location.pathname.slice(0,10) === '/portfolio'
							? <a href='#contact'><Button style={{width: 'auto'}} colorReverse >Contact us</Button></a>
							: <Button style={{width: 'auto'}} colorReverse onClick={()=> navigate('/contact')}>Contact us</Button>
						}
					</Styled.ButtonContainer>
				</>
			)}
			
		</Styled.Header>
		{location.pathname.slice(0,6) === '/blog/' && <Styled.ProgressBar><Styled.ProgressBarPivot pivotPercent={pivotPercent}/></Styled.ProgressBar>}
	</Styled.HeaderContainer>
)
}