import { gsap } from 'gsap';
import { getMoveIndex, isElHasProperty, getStyleProp } from '../chunks';
import propNames from '../propNames';

const contextMode = (cursor, interactElements, isHovered, cursorTarget, lastCursorProp, lastMouseProps) => {
  const props = {
    radius: 20,
    transitionSpeed: 0,
    parallaxIndex: 10,
    hoverPadding: 6,
  };

  const parallaxSpeed = {
    cursor: props.parallaxIndex,
    target: props.parallaxIndex * 1.5,
  };
  
  if (lastCursorProp.current !== undefined) {
    gsap.to(cursor, props.transitionSpeed, lastCursorProp.current);
  }

  const moveCursor = (e) => {
    lastMouseProps.current = {
      x: e.clientX - props.radius / 2,
      y: e.clientY - props.radius / 2,
    }
    // If element is not hovered
    if (!isHovered.current) {
      gsap.to(cursor, props.transitionSpeed, {
        x: e.clientX - props.radius / 2,
        y: e.clientY - props.radius / 2,
      });
      lastCursorProp.current =  {
        x: e.clientX - props.radius / 2,
        y: e.clientY - props.radius / 2,
      }
      // If eleemnt is hovered
    } else {
      const borderRadius = Number(
        window.getComputedStyle(cursorTarget.current).borderRadius.slice(0, -2)
      );
      // For 'LIFT' mode
      if (isElHasProperty(cursorTarget.current, propNames.lift)) {
        gsap.to(cursorTarget.current, props.transitionSpeed, {
          x: getMoveIndex(
            e.clientX,
            cursorTarget.current.getBoundingClientRect().left,
            cursorTarget.current.clientWidth,
            parallaxSpeed.target
          ),
          y: getMoveIndex(
            e.clientY,
            cursorTarget.current.getBoundingClientRect().top,
            cursorTarget.current.clientHeight,
            parallaxSpeed.target
          ),
          scale: 1.1,
          boxShadow: getStyleProp('--ghost-shadow'),
        });
        gsap.to(cursor, props.transitionSpeed, {
          filter: 'blur(8px)',
          x:
            cursorTarget.current.getBoundingClientRect().left +
            (e.clientX -
              cursorTarget.current.getBoundingClientRect().left -
              cursorTarget.current.clientWidth / 2) /
              parallaxSpeed.cursor,
          y:
            cursorTarget.current.getBoundingClientRect().top +
            (e.clientY -
              cursorTarget.current.getBoundingClientRect().top -
              cursorTarget.current.clientHeight / 2) /
              parallaxSpeed.cursor,
          backgroundImage: `radial-gradient(circle at ${
            e.clientX - cursorTarget.current.getBoundingClientRect().left
          }px ${
            e.clientY - cursorTarget.current.getBoundingClientRect().top
          }px, rgba(255,255,255,0.2), rgba(255,255,255,0))`,
        });
        lastCursorProp.current = {
          filter: 'blur(8px)',
          x:
            cursorTarget.current.getBoundingClientRect().left +
            (e.clientX -
              cursorTarget.current.getBoundingClientRect().left -
              cursorTarget.current.clientWidth / 2) /
              parallaxSpeed.cursor,
          y:
            cursorTarget.current.getBoundingClientRect().top +
            (e.clientY -
              cursorTarget.current.getBoundingClientRect().top -
              cursorTarget.current.clientHeight / 2) /
              parallaxSpeed.cursor,
          backgroundImage: `radial-gradient(circle at ${
            e.clientX - cursorTarget.current.getBoundingClientRect().left
          }px ${
            e.clientY - cursorTarget.current.getBoundingClientRect().top
          }px, rgba(255,255,255,0.2), rgba(255,255,255,0))`,
        };
        // For default 'PARALLAX' mode
      } else {
        gsap.to(cursor, props.transitionSpeed, {
          x:
            cursorTarget.current.getBoundingClientRect().left -
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding) +
            (isElHasProperty(cursorTarget.current, propNames.noParallax)
              ? 0
              : (e.clientX -
                  cursorTarget.current.getBoundingClientRect().left -
                  cursorTarget.current.clientWidth / 2) /
                parallaxSpeed.cursor),
          y:
            cursorTarget.current.getBoundingClientRect().top -
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding) +
            (isElHasProperty(cursorTarget.current, propNames.noParallax)
              ? 0
              : (e.clientY -
                  cursorTarget.current.getBoundingClientRect().top -
                  cursorTarget.current.clientHeight / 2) /
                parallaxSpeed.cursor),
          borderRadius:
            borderRadius *
            (isElHasProperty(cursorTarget.current, propNames.noPadding) ? 1 : 1.5),
          width:
            cursorTarget.current.clientWidth +
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding * 2),
          height:
            cursorTarget.current.clientHeight +
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding * 2),
        });
        lastCursorProp.current = {
          x:
            cursorTarget.current.getBoundingClientRect().left -
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding) +
            (isElHasProperty(cursorTarget.current, propNames.noParallax)
              ? 0
              : (e.clientX -
                  cursorTarget.current.getBoundingClientRect().left -
                  cursorTarget.current.clientWidth / 2) /
                parallaxSpeed.cursor),
          y:
            cursorTarget.current.getBoundingClientRect().top -
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding) +
            (isElHasProperty(cursorTarget.current, propNames.noParallax)
              ? 0
              : (e.clientY -
                  cursorTarget.current.getBoundingClientRect().top -
                  cursorTarget.current.clientHeight / 2) /
                parallaxSpeed.cursor),
          borderRadius:
            borderRadius *
            (isElHasProperty(cursorTarget.current, propNames.noPadding) ? 1 : 1.5),
          width:
            cursorTarget.current.clientWidth +
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding * 2),
          height:
            cursorTarget.current.clientHeight +
            (isElHasProperty(cursorTarget.current, propNames.noPadding)
              ? null
              : props.hoverPadding * 2),
        }
        // For 'NO PARALLAX' property
        if (!isElHasProperty(cursorTarget.current, propNames.noParallax)) {
          gsap.to(cursorTarget.current, props.transitionSpeed, {
            x: -getMoveIndex(
              e.clientX,
              cursorTarget.current.getBoundingClientRect().left,
              cursorTarget.current.clientWidth,
              parallaxSpeed.target
            ),
            y: -getMoveIndex(
              e.clientY,
              cursorTarget.current.getBoundingClientRect().top,
              cursorTarget.current.clientHeight,
              parallaxSpeed.target
            ),
          });
        }
      }
    }
  };

  const handleMouseOut = (e) => {
    isHovered.current = false;
    gsap.to(cursor, props.transitionSpeed, {
      x: e.clientX - props.radius / 2,
      y: e.clientY - props.radius / 2,
      width: props.radius,
      height: props.radius,
      borderRadius: '100px',
      scale: 1,
      backgroundImage: 'none',
      filter: 'blur(0px)',
    });
    gsap.to(cursorTarget.current, props.transitionSpeed, {
      x: 0,
      y: 0,
      scale: 1,
      boxShadow: '0 7px 15px rgba(0,0,0,0.0)',
    });
    setTimeout(()=> {
      cursor.classList.remove('c-cursor_active');
      cursor.classList.remove('c-cursor-lift_active');
    },1500) 
  };

  const handleMouseOver = (e) => {
    isHovered.current = true;
    cursorTarget.current = e.target;
    const borderRadius = Number(
      window.getComputedStyle(cursorTarget.current).borderRadius.slice(0, -2)
    );

    if (isElHasProperty(cursorTarget.current, propNames.lift)) {
      cursor.classList.add('c-cursor-lift_active');
      gsap.to(cursor, props.transitionSpeed, {
        borderRadius: borderRadius,
        width: cursorTarget.current.clientWidth,
        height: cursorTarget.current.clientHeight,
        scale: 1.1,
      });
    } else {
      cursor.classList.add('c-cursor_active');
    }
  };

  const handleMouseClick = () => {
    gsap.to(cursor, props.transitionSpeed, lastCursorProp.current);
  }

  const handleScroll = () => {
    const newCursorProps = {
      x: lastMouseProps.current.x,
      y: lastMouseProps.current.y,
      width: props.radius,
      height: props.radius,
      borderRadius: '100px',
      scale: 1,
      backgroundImage: 'none',
      filter: 'blur(0px)',
    }
    gsap.to(cursor, props.transitionSpeed, newCursorProps);
  }
  // Event listeners

  document.addEventListener('mousewheel', handleMouseOut);
  document.addEventListener('click', handleMouseClick)
  document.addEventListener('mousemove', moveCursor);
  document.addEventListener('scroll',handleScroll);

  interactElements.forEach((item) => {
    item.addEventListener('mouseenter', handleMouseOver);
    item.addEventListener('mouseleave', handleMouseOut);
  });

  return function () {
    // remove listeners
    document.removeEventListener('mousewhell',handleMouseOut);
    document.removeEventListener('click', handleMouseClick)
    document.removeEventListener('mousemove', moveCursor);
    document.removeEventListener('scroll',handleScroll);


    interactElements.forEach(item => {
      item.removeEventListener('mouseenter', handleMouseOver);
      item.removeEventListener('mouseleave', handleMouseOut);
    })
  }
};

export default contextMode;
